// Get words by category filter
function getWordsInCategories(categories) {
  if (!categories || categories.length === 0) return WORDS;
  return WORDS.filter(w => categories.includes(w.category));
}

module.exports = { CATEGORIES, WORDS, getWordsInCategories };
